import{_ as e,c as p,o as t,ae as o}from"./chunks/framework.BvcDoAct.js";const l=JSON.parse('{"title":"MANATO (BE:FIRST)","description":"","frontmatter":{},"headers":[],"relativePath":"zh-cn/Management2Extra/01_TalkAboutBMSG/07_MANATO.md","filePath":"zh-cn/Management2Extra/01_TalkAboutBMSG/07_MANATO.md"}'),r={name:"zh-cn/Management2Extra/01_TalkAboutBMSG/07_MANATO.md"};function S(A,a,n,T,M,s){return t(),p("div",null,[...a[0]||(a[0]=[o('<p>Talk about BMSG - 07</p><h1 id="manato-be-first" tabindex="-1">MANATO (BE:FIRST) <a class="header-anchor" href="#manato-be-first" aria-label="Permalink to &quot;MANATO (BE:FIRST)&quot;">​</a></h1><h3 id="创作仿佛延伸于日常生活之中。通过音乐紧密相连的-就是bmsg" tabindex="-1">创作仿佛延伸于日常生活之中。通过音乐紧密相连的，就是BMSG <a class="header-anchor" href="#创作仿佛延伸于日常生活之中。通过音乐紧密相连的-就是bmsg" aria-label="Permalink to &quot;创作仿佛延伸于日常生活之中。通过音乐紧密相连的，就是BMSG&quot;">​</a></h3><p><em>MANATO：2001年4月29日出生，福冈县出身</em><br><br><br></p><p>————对现在的MANATO来说，SKY-HI是怎样的存在？</p><p>他拥有比任何人都更宏大的野心，而且为了接近那个目标所制定的计划与构建都非常细致。比如就BE:FIRST而言，他从一开始就会把“几年后希望达到什么样的状态”这样的未来蓝图详细写在白板上并向我们说明。最近，从JUNON开始启动个人项目、再到接下来是LEO，这样的安排其实也都是有意义的。包括执行这些计划后会产生怎样的结果，也都在他的计算之中。等到事后回顾时，还能发现那些伏笔，这种带有娱乐性的设计在内，让人完全无法想象社长到底看到了多远，是个很不可思议的人。</p><p>————你觉得他特别厉害的地方是？</p><p>全部吧。不过日高曾对我说过，“你大概会在25～26岁的时候为歌词而烦恼”。虽然现在在制作方面，包括歌词，也会有卡住的时候，但他说过类似“你可能还有没经历过的事情，也要考虑到未来，我觉得你还能再往更深的地方走”这样的话。那还是两三年后的事，我也不知道到时候自己会是什么状态，总之就想着先踏踏实实地生活吧（笑）。</p><p>————和SKY-HI的一对一会议一般会聊些什么？</p><p>我们7个人会分别去日高家里，能喝酒的成员会一边喝一边聊，而我则是和他一起看各种艺人的MV（笑）。</p><p>————（笑）感觉像是和喜欢音乐的朋友在喝酒。</p><p>真的就是那种感觉（笑）。可能他对每个人的相处方式都不一样吧，而我本身是比较乐观、不太容易烦恼的类型，所以基本上就是单纯聊喜欢的音乐比较多。另外，日高也非常喜欢ShowMinorSavage，甚至会说“我也想加入”，还会提出“希望你们做这种风格的歌”之类的建议。</p><p>————在「BMSG FES&#39;24」表演《Tiger Style》的时候，SKY-HI在沙龙区和你互动，但你面无表情地无视了他（笑）。</p><p>他突然一直来搭话，我也挺惊讶的（笑）。而且我想着“这绝对会被镜头拍到吧”，所以我也想留下点记忆点，就做了那样的反应。</p><p>————如果是出道初期应该做不到吧。</p><p>做不到啊（笑）。日高给人的感觉是，不只是对BE:FIRST，而是对每一个人都抱有信任。音乐层面明显出错的情况也减少了很多，所以比起社长与艺人的关系，更像是在同一个团队里的伙伴那种感觉在和我们相处。《Tiger Style》的时候我尤其有这种感受。</p><p>————成员越来越参与创作，这点也有关系吗？</p><p>是的。与其说是在制作的时候集中深入讨论，不如说是在事务所偶然碰到的时候聊聊下一首歌，或者让我们听一些非常初期的demo，所以会有一种“创作就在日常生活延长线上”的感觉。最近聊得比较多的是舞蹈，比如“想做这种舞蹈的话，那就做这样的曲子吧”之类的。</p><p>在搬到现在这个事务所之前，有时候也会觉得“最近好像没见到日高啊”，但现在在同一栋大楼里，自然见面的机会就变多了。也一起在健身房训练过，前阵子我在录音室练吉他的时候他也来找我，简单聊了几句。我觉得他是尽可能想要多进行沟通，而正因为有这样的沟通，才更容易去构建未来的蓝图吧。</p><p>————正因为距离近，才能做出更精准的制作。</p><p>我觉得绝对是这样。他也经常来活动和音乐节现场，比如在创作歌曲的时候会对我们说“可以做到像之前那个活动那样的程度”，这样我们也更容易去理解。他还去了MAZZEL最终场的大阪公演，也在做《No No Girls》，明明已经非常忙了，但依然会认真地面对每一个人，这点真的很让人开心。</p><p>————什么时候会让你觉得，作为BMSG的艺人很自豪？</p><p>说实话，是一直都会有这种感觉。尤其是在参加外部活动的时候更明显。比如之前的SBS活动（SBS INKIGAYO LIVE in TOKYO）也是，不只是想着要展现BE:FIRST的魅力，同时因为我们是BMSG推出的第一组艺人，也会有一种“代表整个BMSG”的意识。不过我不太想给自己太大压力，所以也不会让自己背负过头。另外，在「BMSG FES&#39;24」看BMSG POSSE的演出时我特别有感触，不分立场和年龄，大家只是因为“音乐”这个共同点而在表演。让我觉得整个BMSG真的都是通过音乐连接在一起的关系。ShowMinorSavage也是这样，自家艺人之间的合作很多，我觉得这也体现了BMSG的凝聚力。</p><h3 id="看着练习生-会想起当时参加选秀的自己" tabindex="-1">看着练习生，会想起当时参加选秀的自己 <a class="header-anchor" href="#看着练习生-会想起当时参加选秀的自己" aria-label="Permalink to &quot;看着练习生，会想起当时参加选秀的自己&quot;">​</a></h3><p>————说到MANATO，给人一种在练习生中很受憧憬的印象。</p><p>没有没有，太不敢当了。憧憬对象选错了吧（笑）。不过还是很开心的。我自己也是因为有憧憬才开始做音乐的人，也希望年轻人能更多地去接触音乐。而且我也有一个梦想，就是等到自己到了日高那样的年纪时，能和那些曾经让我产生憧憬的人合作。所以当年轻人对我说“想成为像MANATO那样的人”的时候，会让我觉得非常有成就感。</p><p>————会有人向你请教建议吗？</p><p>会的。有一次我在健身房，正好有3个练习生进来，说他们要在TRAINEE SHOWCASE上表演《Boom Boom Back》和《Message》。《Message》这首歌需要唱比较高的音，对正处在变声期的人来说其实很难，他们就问我“要怎样才能把声音发得更好听？”这种非常笼统的问题（笑）。我就先补充说“每个人适合的方法都不一样，如果有觉得共鸣的地方可以试着重点去练”，然后再把我自己觉得比较容易发声的方法告诉他们。那时候SHUNTO也在，但他一直把事情丢给我，还说什么“我也想听”，开始站到练习生那边去了，我心里就想“这家伙！”（笑）。不过真的能感受到练习生的热情。去录音室的话一定有人在练习，而且他们也会主动去找日高请教。无论唱歌还是舞蹈，大家都真的很厉害。我也希望他们继续努力，同时也会激励自己要更努力。甚至让我都有点想去看TRAINEE SHOWCASE了，很好奇他们会把《Message》呈现成什么样。</p><p>————有感受到BMSG特有的共通点吗？</p><p>与其说是共通点，不如说我们现在当然也在努力，但在选秀的时候真的是非常自律、非常拼命。我在合宿期间每天都会晨练。看到他们就会想起那时候的自己，觉得“当时真的挺辛苦的”。</p><p>————一起参加过合宿的RUI和TAIKI会参加《THE LAST PIECE》，你有什么想法？</p><p>希望他们加油吧。KANON也是，那三个人虽然挂着练习生的头衔，但其实已经发过作品，也在台前有不少活动。我希望他们不要太在意这些，不要勉强自己去逞强，能够自然地去挑战。在这个基础上，再去思考“为了让自己更进一步还能做什么”，我觉得就会顺利很多。虽然我实际上没有参加过社团活动，但在《THE FIRST》的时候，会让我有一种“社团大概就是这样的感觉吧”的快乐。在疫情期间，很难有机会让一群拥有同样梦想的人聚在一起，所以那次选秀是一个非常有刺激性的环境。现在BMSG已经有了自己的大楼，有能够好好训练的环境，我觉得他们也有更多可以专注、严格要求自己的时间。所以希望他们能够不留遗憾地去努力，我也会全力支持他们。</p><blockquote><h3 id="from-sky-hi" tabindex="-1">from SKY-HI <a class="header-anchor" href="#from-sky-hi" aria-label="Permalink to &quot;from SKY-HI&quot;">​</a></h3><p>虽然有点难表达，但在那23人之中，他可能是最不执着于“走红”这件事的人。</p><p>他只是凭着对音乐的真诚与诚实在做这件事，这既是MANATO的强大之处，也是他的美。我最希望的是他能一直保持这一点。不过，“想要被更多人知道”在某种意义上其实也是对支持自己的人一种回馈。如果在不迷失本质的前提下，能够更加强烈地去意识到“想要扩大、想要被更多人看见”，那我觉得还能看到一个前所未见、非常惊人的MANATO。“居然还有之后吗！？”可能会让人这么想（笑），但确实还有。</p><p>MANATO今后还会变得更加惊人。</p></blockquote>',33)])])}const h=e(r,[["render",S]]);export{l as __pageData,h as default};
